  ('colonel-bd450684-moex-00005', 'colonel-bd450684', 'colonel-bd450684-moex-111-40c26c04', 'sub-colonel-bd450684-02', NULL, 'essay', '憲法第 15條規定：「人民之生存權、工作權及財產權，應予保障。」而
律師法第28 條則明文規定：「司法人員自離職之日起 3 年內，不得在其
離職前 3 年內曾任職務之法院或檢察署執行律師職務。但其因停職、休
職或調職等原因離開上開法院或檢察署已滿 3年者，不在此限。」試問
上述律師法條文是否構成違憲？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "3f5714614791", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "805", "s": "0306", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中華民國憲法與英文", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "廉政"}'::jsonb, NULL),
